import React, { useEffect, useState } from 'react';
import {
  adminGetStats, adminGetMetrics, adminGetUsers,
  adminGetLogs, adminSuspendUser, adminActivateUser,
  adminDeleteUser, adminGetDatasetInfo, adminUploadDataset
} from '../services/api';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import toast from 'react-hot-toast';
import './Admin.css';

const COLORS = ['#ef4444', '#f59e0b', '#10b981', '#9ca3af'];

export default function Admin() {
  const [tab, setTab] = useState('overview');
  const [stats, setStats] = useState(null);
  const [metrics, setMetrics] = useState(null);
  const [users, setUsers] = useState([]);
  const [logs, setLogs] = useState([]);
  const [datasetInfo, setDatasetInfo] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    adminGetStats().then((r) => setStats(r.data)).catch(() => {});
    adminGetMetrics().then((r) => setMetrics(r.data)).catch(() => {});
  }, []);

  useEffect(() => {
    if (tab === 'users' && users.length === 0) {
      adminGetUsers().then((r) => setUsers(r.data)).catch(() => {});
    }
    if (tab === 'logs' && logs.length === 0) {
      adminGetLogs(100).then((r) => setLogs(r.data)).catch(() => {});
    }
    if (tab === 'dataset') {
      adminGetDatasetInfo().then((r) => setDatasetInfo(r.data)).catch(() => {});
    }
  }, [tab]);

  const handleSuspend = async (id) => {
    try { await adminSuspendUser(id); setUsers(users.map(u => u.id === id ? { ...u, status: 'suspended' } : u)); toast.success('User suspended'); }
    catch { toast.error('Failed'); }
  };
  const handleActivate = async (id) => {
    try { await adminActivateUser(id); setUsers(users.map(u => u.id === id ? { ...u, status: 'active' } : u)); toast.success('User activated'); }
    catch { toast.error('Failed'); }
  };
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this user?')) return;
    try { await adminDeleteUser(id); setUsers(users.filter(u => u.id !== id)); toast.success('User deleted'); }
    catch { toast.error('Failed'); }
  };

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const fd = new FormData(); fd.append('file', file);
    setLoading(true);
    try {
      const res = await adminUploadDataset(fd);
      toast.success(`Dataset uploaded! ${res.data.rows} rows loaded.`);
      adminGetDatasetInfo().then((r) => setDatasetInfo(r.data)).catch(() => {});
    } catch { toast.error('Upload failed.'); }
    finally { setLoading(false); }
  };

  const metricsBarData = metrics ? [
    { name: 'Found', value: metrics.found_interactions },
    { name: 'Not Found', value: metrics.not_found },
    { name: 'High', value: metrics.high_risk_count },
    { name: 'Moderate', value: metrics.moderate_risk_count },
    { name: 'Low', value: metrics.low_risk_count },
  ] : [];

  const riskPieData = metrics ? [
    { name: 'High', value: metrics.high_risk_count },
    { name: 'Moderate', value: metrics.moderate_risk_count },
    { name: 'Low', value: metrics.low_risk_count },
  ] : [];

  const tabs = ['overview', 'users', 'logs', 'dataset'];

  return (
    <div className="main-content">
      <div className="admin-page fade-up">
        <div className="admin-header">
          <div>
            <h1 className="section-title">Admin Panel</h1>
            <p className="section-sub">MediMind system management</p>
          </div>
        </div>

        {/* Tabs */}
        <div className="admin-tabs">
          {tabs.map((t) => (
            <button key={t} className={`admin-tab ${tab === t ? 'active' : ''}`} onClick={() => setTab(t)}>
              {t === 'overview' && '📊 '}
              {t === 'users' && '👥 '}
              {t === 'logs' && '📋 '}
              {t === 'dataset' && '📁 '}
              {t.charAt(0).toUpperCase() + t.slice(1)}
            </button>
          ))}
        </div>

        {/* Overview */}
        {tab === 'overview' && (
          <div className="admin-overview">
            <div className="admin-stats-grid">
              {stats && [
                { label: 'Total Users', val: stats.total_users, color: 'var(--green-600)' },
                { label: 'Active Users', val: stats.active_users, color: 'var(--green-500)' },
                { label: 'Suspended', val: stats.suspended_users, color: '#ef4444' },
                { label: 'Total Predictions', val: stats.total_predictions, color: 'var(--green-700)' },
                { label: 'Dataset Rows', val: stats.dataset_size?.toLocaleString(), color: 'var(--green-800)' },
              ].map((s) => (
                <div key={s.label} className="admin-stat card">
                  <span className="admin-stat-val" style={{ color: s.color }}>{s.val}</span>
                  <span className="admin-stat-lbl">{s.label}</span>
                </div>
              ))}
            </div>

            {metrics && (
              <div className="admin-charts">
                <div className="card">
                  <h3 className="chart-title">Prediction Overview</h3>
                  <ResponsiveContainer width="100%" height={220}>
                    <BarChart data={metricsBarData}>
                      <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                      <YAxis tick={{ fontSize: 11 }} />
                      <Tooltip />
                      <Bar dataKey="value" fill="var(--green-500)" radius={[6, 6, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
                <div className="card">
                  <h3 className="chart-title">Risk Level Distribution</h3>
                  <ResponsiveContainer width="100%" height={220}>
                    <PieChart>
                      <Pie data={riskPieData} cx="50%" cy="50%" outerRadius={80} dataKey="value"
                        label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}>
                        {riskPieData.map((_, i) => <Cell key={i} fill={COLORS[i]} />)}
                      </Pie>
                      <Legend />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Users */}
        {tab === 'users' && (
          <div className="card">
            <div className="table-wrap">
              <table>
                <thead>
                  <tr><th>Name</th><th>Email</th><th>Role</th><th>Status</th><th>Joined</th><th>Actions</th></tr>
                </thead>
                <tbody>
                  {users.map((u) => (
                    <tr key={u.id}>
                      <td>{u.name} {u.is_admin && <span className="badge badge-low" style={{fontSize:10}}>Admin</span>}</td>
                      <td>{u.email}</td>
                      <td style={{ textTransform: 'capitalize' }}>{u.role?.replace('_', ' ')}</td>
                      <td><span className={`badge badge-${u.status}`}>{u.status}</span></td>
                      <td>{u.created_at ? new Date(u.created_at).toLocaleDateString() : '—'}</td>
                      <td>
                        <div className="action-btns">
                          {u.status === 'active' && !u.is_admin && (
                            <button className="btn btn-sm" style={{ background: '#fef3c7', color: '#92400e' }}
                              onClick={() => handleSuspend(u.id)}>Suspend</button>
                          )}
                          {u.status === 'suspended' && (
                            <button className="btn btn-sm btn-primary" onClick={() => handleActivate(u.id)}>Activate</button>
                          )}
                          {!u.is_admin && (
                            <button className="btn btn-sm btn-danger" onClick={() => handleDelete(u.id)}>Delete</button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Logs */}
        {tab === 'logs' && (
          <div className="card">
            <div className="table-wrap">
              <table>
                <thead>
                  <tr><th>#</th><th>Drug 1</th><th>Drug 2</th><th>Risk</th><th>User</th><th>Date</th></tr>
                </thead>
                <tbody>
                  {logs.map((l) => (
                    <tr key={l.id}>
                      <td>{l.id}</td>
                      <td style={{ textTransform: 'capitalize' }}>{l.drug1}</td>
                      <td style={{ textTransform: 'capitalize' }}>{l.drug2}</td>
                      <td><span className={`badge badge-${(l.risk_level || 'unknown').toLowerCase()}`}>{l.risk_level || '—'}</span></td>
                      <td>{l.user_id || <span style={{ color: 'var(--gray-400)' }}>Guest</span>}</td>
                      <td>{l.created_at ? new Date(l.created_at).toLocaleDateString() : '—'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Dataset */}
        {tab === 'dataset' && (
          <div className="dataset-tab">
            {datasetInfo && (
              <div className="dataset-stats">
                <div className="card"><span className="admin-stat-val">{datasetInfo.total_pairs?.toLocaleString()}</span><span className="admin-stat-lbl">Total Pairs</span></div>
                <div className="card"><span className="admin-stat-val" style={{ color: 'var(--green-600)' }}>{datasetInfo.with_interactions?.toLocaleString()}</span><span className="admin-stat-lbl">With Interactions</span></div>
                <div className="card"><span className="admin-stat-val" style={{ color: 'var(--gray-500)' }}>{datasetInfo.no_interaction?.toLocaleString()}</span><span className="admin-stat-lbl">No Interaction</span></div>
              </div>
            )}
            <div className="card upload-card">
              <h3 className="chart-title">Upload New Dataset</h3>
              <p style={{ fontSize: 13, color: 'var(--gray-500)', margin: '8px 0 18px' }}>
                Upload a CSV file with columns: drug1, drug2, interaction_description, interaction_effect, interaction_type, label, source, pair_key
              </p>
              <label className="upload-label">
                {loading ? <><span className="spinner" style={{ width: 18, height: 18 }} /> Uploading...</> : '📁 Choose CSV File'}
                <input type="file" accept=".csv" onChange={handleUpload} style={{ display: 'none' }} disabled={loading} />
              </label>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
